// Phase 2 — AI-generated Shortcut endpoint
//
// POST /api/ios/build-shortcut
//   Body: { title: String, dsl: String }
//   Response 200: { url: String }
//   Response 4xx/5xx: { error: String }
//
// Flow:
//   1. Receive Cherri DSL from iOS app (generated by Apple FM on-device)
//   2. Write DSL to a temp file on the harness machine
//   3. SCP the DSL to the configured Mac signing host
//   4. SSH the Mac: run `cherri /tmp/<id>.cherri -s anyone`
//   5. Cherri uses Shortcuts CLI on Mac (or HubSign fallback) to sign
//   6. SCP signed .shortcut back to harness
//   7. Host the signed file at /api/ios/build-shortcut/<id>.shortcut
//      with a 5-minute TTL
//   8. Return the URL to iOS
//
// Mac signing config via env vars (set in harness config.json or env):
//   HARNESS_MAC_SIGN_HOST   — SSH hostname (e.g. user@FF125.macincloud.com)
//   HARNESS_MAC_SIGN_TMPDIR — temp dir on Mac (default: /tmp)
//   HARNESS_MAC_CHERRI_BIN  — path to cherri on Mac (default: ~/bin/cherri)
//
// Authentication: same Bearer middleware as other ios-router endpoints.

import { promises as fs, existsSync, readFileSync } from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';
import os from 'node:os';
import crypto from 'node:crypto';
import { Client as SSHClient } from 'ssh2';
import { log } from '../logger.js';
import { spawnClaude } from '../claude-runner.js';

// MARK: - .env loader (bypass Git Bash MSYS path translation)
//
// On Windows + Git Bash, `set -a; source .env; set +a` mangles POSIX paths
// inside .env values: `HARNESS_MAC_SIGN_TMPDIR=/tmp` becomes
// `C:/Users/arman/AppData/Local/Temp` by the time Node sees it. This breaks
// SFTP because the "remote" path is now a Windows local path.
//
// Fix: read .env directly in Node with a tiny parser. Real env wins over
// the file (so production deploys can override via real env). Idempotent.

(function loadEnvFromFileOnce() {
  try {
    const here = path.dirname(fileURLToPath(import.meta.url));
    const envPath = path.resolve(here, '..', '.env');
    if (!existsSync(envPath)) return;
    const text = readFileSync(envPath, 'utf8');
    for (const rawLine of text.split(/\r?\n/)) {
      const line = rawLine.replace(/^\s*export\s+/, '');
      if (!line || line.startsWith('#')) continue;
      const m = line.match(/^\s*([A-Z_][A-Z0-9_]*)\s*=\s*(.*?)\s*$/i);
      if (!m) continue;
      const key = m[1];
      let value = m[2];
      if ((value.startsWith('"') && value.endsWith('"'))
          || (value.startsWith("'") && value.endsWith("'"))) {
        value = value.slice(1, -1);
      }
      // Only set HARNESS_MAC_* path-shaped vars from file IF the current
      // env value looks bash-mangled (Windows abs path) OR is missing.
      // Real env vars from a clean shell win.
      const cur = process.env[key];
      const isPathShaped = key.startsWith('HARNESS_MAC_') && /(?:_HOST$|_TMPDIR$|_BIN$|_KEY$|_PATH$)/i.test(key);
      const looksMangled = typeof cur === 'string' && /^[A-Z]:[\\/]/i.test(cur);
      if (cur == null || (isPathShaped && looksMangled)) {
        process.env[key] = value;
      }
    }
  } catch (e) {
    log(`[build-shortcut][warn] .env load failed: ${e.message}`);
  }
})();

const logger = {
  info: (msg, meta) => log(`[build-shortcut] ${msg}`, meta || ''),
  warn: (msg, meta) => log(`[build-shortcut][warn] ${msg}`, meta || ''),
  error: (msg, meta) => log(`[build-shortcut][error] ${msg}`, meta || ''),
};

// MARK: - In-memory hosted files (TTL 5 min)

/**
 * Map of <id> → { filePath: String, expiresAt: Date }
 * Used to serve the signed .shortcut file after build. Auto-pruned on every
 * GET to keep memory bounded.
 */
const hostedFiles = new Map();
const FILE_TTL_MS = 5 * 60 * 1000;  // 5 minutes

function pruneExpired() {
  const now = Date.now();
  for (const [id, entry] of hostedFiles.entries()) {
    if (entry.expiresAt < now) {
      hostedFiles.delete(id);
      fs.unlink(entry.filePath).catch(() => {});
    }
  }
}

// MARK: - Config

function macSignHost() {
  return process.env.HARNESS_MAC_SIGN_HOST || '';
}

function macTmpDir() {
  return process.env.HARNESS_MAC_SIGN_TMPDIR || '/tmp';
}

function macCherriBin() {
  return process.env.HARNESS_MAC_CHERRI_BIN || '~/bin/cherri';
}

// MARK: - SSH/SFTP via ssh2 (pure JS, cross-platform)
//
// We don't shell out to ssh/scp because that path is fragile on Windows:
// MSYS scp from Git Bash mangles `host:/path` via path conversion, Windows
// OpenSSH cares about strict permissions on ~/.ssh/config, PATH may resolve
// to either binary depending on shell, etc. ssh2 talks the SSH protocol
// directly in Node — identical behavior on Win/Mac/Linux, zero subprocess.
//
// Connection config — three env vars, that's it:
//   HARNESS_MAC_SIGN_HOST     "user@host[:port]"  (e.g. user297422@FF125.macincloud.com)
//   HARNESS_MAC_SIGN_KEY      path to private key (default: ~/.ssh/id_ed25519, fallback ~/.ssh/id_rsa)
//   HARNESS_MAC_SIGN_KEY_PASSPHRASE   optional passphrase if the key is encrypted
//
// No SSH config parsing, no host aliases — full target in one env var.

/**
 * Parse "[user@]host[:port]" into { user, host, port }. user defaults to
 * current OS username; port defaults to 22.
 */
function parseSshTarget(target) {
  const m = String(target || '').trim().match(/^(?:([^@]+)@)?([^:]+)(?::(\d+))?$/);
  if (!m) throw new Error(`HARNESS_MAC_SIGN_HOST invalid: '${target}'. Expected user@host[:port].`);
  return {
    user: m[1] || os.userInfo().username,
    host: m[2],
    port: m[3] ? parseInt(m[3], 10) : 22,
  };
}

function expandHome(p) {
  if (!p) return p;
  if (p.startsWith('~')) return path.join(os.homedir(), p.slice(1));
  return p;
}

/**
 * Locate the SSH private key. Honor env override; otherwise try the two
 * common defaults (ed25519, rsa) in user's ~/.ssh dir.
 */
function findPrivateKey() {
  const explicit = process.env.HARNESS_MAC_SIGN_KEY;
  if (explicit) {
    const resolved = expandHome(explicit);
    if (!existsSync(resolved)) {
      throw new Error(`HARNESS_MAC_SIGN_KEY points to a missing file: ${resolved}`);
    }
    return resolved;
  }
  const candidates = [
    path.join(os.homedir(), '.ssh', 'id_ed25519'),
    path.join(os.homedir(), '.ssh', 'id_rsa'),
  ];
  for (const c of candidates) if (existsSync(c)) return c;
  throw new Error('No SSH private key found. Set HARNESS_MAC_SIGN_KEY or place a key at ~/.ssh/id_ed25519 (or id_rsa).');
}

/**
 * Open an SSH connection to the configured Mac signer. Resolves with a
 * connected ssh2 Client; reject with descriptive Error otherwise. Caller
 * must conn.end() when done.
 */
function openSshConnection() {
  const target = macSignHost();
  if (!target) {
    return Promise.reject(new Error('HARNESS_MAC_SIGN_HOST not configured. Set it to user@host[:port] to enable AI-generated Shortcuts.'));
  }
  const { user, host, port } = parseSshTarget(target);
  const keyPath = findPrivateKey();
  const privateKey = readFileSync(keyPath);
  const passphrase = process.env.HARNESS_MAC_SIGN_KEY_PASSPHRASE || undefined;

  logger.info(`ssh connect ${user}@${host}:${port} (key=${path.basename(keyPath)})`);

  return new Promise((resolve, reject) => {
    const conn = new SSHClient();
    const cleanup = (err) => { try { conn.end(); } catch {} reject(err); };
    const timer = setTimeout(() => cleanup(new Error('SSH connect timed out after 15s')), 15000);
    conn.on('ready', () => { clearTimeout(timer); resolve(conn); });
    conn.on('error', (e) => { clearTimeout(timer); cleanup(new Error(`SSH connect failed: ${e.message}`)); });
    conn.connect({
      host, port, username: user,
      privateKey, passphrase,
      readyTimeout: 15000,
      keepaliveInterval: 5000,
      // We trust the configured host. For multi-tenant production, switch to
      // hostVerifier with a pinned fingerprint from env.
    });
  });
}

/** Promise wrapper for conn.sftp(). */
function getSftp(conn) {
  return new Promise((resolve, reject) => {
    conn.sftp((err, sftp) => err ? reject(err) : resolve(sftp));
  });
}

/** Promise wrapper for sftp.fastPut(local, remote). */
function sftpPut(sftp, local, remote) {
  return new Promise((resolve, reject) => {
    sftp.fastPut(local, remote, (err) => err ? reject(err) : resolve());
  });
}

/** Promise wrapper for sftp.fastGet(remote, local). */
function sftpGet(sftp, remote, local) {
  return new Promise((resolve, reject) => {
    sftp.fastGet(remote, local, (err) => err ? reject(err) : resolve());
  });
}

/**
 * Run a remote command. Resolves with { code, stdout, stderr }. Never
 * rejects on non-zero exit — caller decides what to do.
 */
function sshExec(conn, command, timeoutMs = 30000) {
  return new Promise((resolve, reject) => {
    conn.exec(command, (err, stream) => {
      if (err) return reject(err);
      let stdout = '', stderr = '';
      const timer = setTimeout(() => {
        try { stream.signal('KILL'); } catch {}
        reject(new Error(`Remote command timed out: ${command}`));
      }, timeoutMs);
      stream.on('data', (d) => stdout += d.toString('utf8'));
      stream.stderr.on('data', (d) => stderr += d.toString('utf8'));
      stream.on('close', (code, signal) => {
        clearTimeout(timer);
        resolve({ code: code ?? -1, stdout, stderr, signal });
      });
    });
  });
}

// MARK: - Compile + sign pipeline

/**
 * Compiles + signs the given Cherri DSL on the configured Mac.
 * Returns Buffer of the signed .shortcut file bytes.
 *
 * Strategy:
 *   1. Write DSL to local tmp file
 *   2. scp DSL to Mac at ${macTmpDir()}/<id>.cherri
 *   3. ssh Mac: ${macCherriBin()} <path>.cherri -s anyone
 *      → produces sibling <path>.shortcut on Mac
 *   4. scp .shortcut back from Mac to local
 *   5. Return Buffer
 *
 * Each step's failure surfaces as Error → caller turns into 5xx response.
 */
async function compileAndSignOnMac(id, dsl) {
  const localDir = path.join(os.tmpdir(), 'gigi-shortcuts');
  await fs.mkdir(localDir, { recursive: true });
  const localDsl = path.join(localDir, `${id}.cherri`);
  const localShortcut = path.join(localDir, `${id}.shortcut`);
  const macDsl = `${macTmpDir()}/${id}.cherri`;
  const macShortcut = `${macTmpDir()}/${id}.shortcut`;

  logger.info(`compiling ${id} — DSL ${dsl.length} bytes`);

  await fs.writeFile(localDsl, dsl, 'utf8');
  logger.info(`${id} wrote local DSL at ${localDsl} (exists=${existsSync(localDsl)}, ${dsl.length}B)`);

  const conn = await openSshConnection();
  try {
    const sftp = await getSftp(conn);
    logger.info(`${id} sftp opened`);

    // 1. Upload DSL
    try {
      await sftpPut(sftp, localDsl, macDsl);
      logger.info(`${id} sftp put ok: ${localDsl} -> ${macDsl}`);
    } catch (e) {
      throw new Error(`SFTP upload failed (local=${localDsl} remote=${macDsl}): ${e.message}`);
    }

    // 2. Compile + sign on Mac. cherri writes the signed .shortcut next to
    //    the DSL. 2>&1 ensures we capture any signing warnings/errors.
    const cherriCmd = `${macCherriBin()} ${macDsl} -s anyone 2>&1`;
    const exec1 = await sshExec(conn, cherriCmd, 45000);
    logger.info(`${id} cherri exit=${exec1.code} stdout=${exec1.stdout.slice(0,200).replace(/\s+/g,' ')}`);
    if (exec1.code !== 0) {
      throw new Error(`cherri failed (exit ${exec1.code}): ${(exec1.stdout + exec1.stderr).slice(0, 500)}`);
    }

    // 3. Download signed file
    try {
      await sftpGet(sftp, macShortcut, localShortcut);
      logger.info(`${id} sftp get ok: ${macShortcut} -> ${localShortcut}`);
    } catch (e) {
      throw new Error(`SFTP download failed (remote=${macShortcut} local=${localShortcut}): ${e.message}`);
    }

    // 4. Cleanup Mac tmp (fire-and-forget — non-fatal if it fails)
    sshExec(conn, `rm -f ${macDsl} ${macShortcut}`, 5000)
      .catch((e) => logger.warn(`mac cleanup failed: ${e.message}`));
  } finally {
    try { conn.end(); } catch {}
  }

  const buf = await fs.readFile(localShortcut);
  logger.info(`compiled ${id} — signed ${buf.length} bytes`);
  return { path: localShortcut, bytes: buf };
}

// MARK: - Cherri vocabulary
//
// Each entry maps a logical action name to:
//   - template:  Cherri DSL source with ${param} placeholders
//   - include:   Cherri `#include 'actions/X'` directive required for this
//                action (null = basic, auto-included by cherri)
//
// Discovered empirically by compiling single-action DSLs against cherri
// v2.2.0 and reading the "requires include" diagnostics. Keep this map as
// the SINGLE SOURCE OF TRUTH — the iOS side does not duplicate it.

const CHERRI_VOCABULARY = {
  // Basic — no include required
  showResult:       { template: 'show(${text})',                include: null },
  showNotification: { template: 'showNotification(${text})',    include: null },
  waitSeconds:      { template: 'wait(${seconds})',             include: null },
  openApp:          { template: 'openApp(${appID})',            include: null },

  // Settings (brightness/volume) — 0..1 floats
  setBrightness:    { template: 'setBrightness(${brightness})', include: 'settings' },
  setVolume:        { template: 'setVolume(${level})',          include: 'settings' },

  // Camera torch — INTENTIONALLY UNSUPPORTED.
  //
  // Cherri 2.2.0 stdlib has `setLEDFlash` under actions/a11y, but it maps to
  // `com.apple.AccessibilityUtilities.AXSettingsShortcuts.AXToggleLEDFlashIntent`
  // — the accessibility "LED Flash for Alerts" toggle, NOT the camera
  // flashlight (`is.workflow.actions.flashlight`). The silent failure of
  // the previous mapping wasted real device-debugging time; we now fail
  // loudly at the plan phase so the user knows immediately.
  //
  // Fix path: when cherri ships a stdlib function for the camera torch
  // action (or the harness gains a non-cherri plist injector), swap these
  // entries back to a working `{ template, include }` shape.
  torchOn:          { unsupported: 'Flashlight Shortcuts (torch on) are not yet supported by this builder — the underlying compiler has no mapping for the camera-flashlight action. Try a different intent for now.' },
  torchOff:         { unsupported: 'Flashlight Shortcuts (torch off) are not yet supported by this builder — the underlying compiler has no mapping for the camera-flashlight action. Try a different intent for now.' },

  // Sharing
  setClipboard:     { template: 'setClipboard(${text})',        include: 'sharing' },

  // Music — pause/resume/skip without a specific track
  playMusic:        { template: 'play()',                       include: 'music' },
  pauseMusic:       { template: 'pause()',                      include: 'music' },
  skipForward:      { template: 'skipFwd()',                    include: 'music' },
  skipBackward:     { template: 'skipBack()',                   include: 'music' },

  // Text → speech
  speakText:        { template: 'speak(${text})',               include: 'text' },
};

// Float [0..1] placeholders vs. integer/bare numeric placeholders.
const CHERRI_FLOAT01_PARAMS  = new Set(['brightness', 'level']);
const CHERRI_NUMERIC_PARAMS  = new Set(['seconds', 'minutes']);

function cherriFormatValue(raw, placeholderName) {
  const trimmed = String(raw ?? '').trim();
  if (CHERRI_FLOAT01_PARAMS.has(placeholderName)) {
    let n = Number(trimmed);
    if (!Number.isFinite(n)) n = 0.5;
    if (n > 1) n = n / 100;                 // accept 0-100 input gracefully
    n = Math.max(0, Math.min(1, n));
    return n.toString();
  }
  if (CHERRI_NUMERIC_PARAMS.has(placeholderName)) {
    return Number.isFinite(Number(trimmed)) && trimmed !== '' ? trimmed : '0';
  }
  return '"' + trimmed.replace(/"/g, '\\"') + '"';
}

function cherriSubstitute(template, params) {
  return template.replace(/\$\{([a-zA-Z_][a-zA-Z0-9_]*)\}/g, (_m, name) => {
    return cherriFormatValue(params?.[name], name);
  });
}

/**
 * Translates a Claude-produced JSON action list into a complete Cherri
 * DSL source file (with the required #include directives prepended).
 * Returns null if any action is outside the vocabulary — caller surfaces
 * an error to iOS so the user can rephrase.
 */
function translateActionsToCherri(title, actions) {
  if (!Array.isArray(actions) || actions.length === 0) return null;

  // First pass — validate + collect unique includes (order doesn't matter
  // to cherri).
  const includes = new Set();
  for (const spec of actions) {
    const entry = CHERRI_VOCABULARY[spec?.action];
    if (!entry) {
      logger.warn(`unknown cherri action '${spec?.action}' — abort translation`);
      return null;
    }
    if (entry.unsupported) {
      // Loud-fail: caller's try/catch surfaces this message to iOS so the
      // user sees a clear explanation instead of a silently broken Shortcut.
      logger.warn(`action '${spec?.action}' is intentionally unsupported: ${entry.unsupported}`);
      const err = new Error(entry.unsupported);
      err.code = 'CHERRI_ACTION_UNSUPPORTED';
      throw err;
    }
    if (entry.include) includes.add(entry.include);
  }

  const lines = [];
  for (const cat of includes) {
    lines.push(`#include 'actions/${cat}'`);
  }
  if (includes.size) lines.push('');

  const cleanTitle = String(title || '').trim();
  if (cleanTitle) {
    lines.push(`// ${cleanTitle}`);
    lines.push(`// Generated by GIGI via Claude ${new Date().toISOString()}`);
    lines.push('');
  }

  for (const spec of actions) {
    const entry = CHERRI_VOCABULARY[spec.action];
    lines.push(cherriSubstitute(entry.template, spec.params || {}));
  }
  return lines.join('\n');
}

// MARK: - Claude composer
//
// One-shot Claude CLI invocation to synthesize { title, actions[] } from a
// raw user request. No session, no memory injection — fresh ephemeral
// process per request, JSON-only output enforced via prompt + tight system.
// Claude is dramatically more reliable than Apple FM on-device for this
// structured composition task (ADR-0014 follow-up).

const COMPOSER_SYSTEM_PROMPT = `You are GIGI's Shortcut composer. The user wants to build an iOS Shortcut from a natural-language request. Your job: output a single JSON object describing the shortcut.

Available actions (use EXACTLY these names, no others):
- showResult { text }                — show a message on screen
- showNotification { text }          — system notification
- speakText { text }                 — speak the text out loud
- waitSeconds { seconds }            — pause N seconds (integer)
- setClipboard { text }              — copy text to clipboard
- torchOn {}                         — turn flashlight on
- torchOff {}                        — turn flashlight off
- setBrightness { brightness }       — screen brightness 0..1 (e.g. "0.8")
- setVolume { level }                — system volume 0..1 (e.g. "0.5")
- playMusic {}                       — resume music playback
- pauseMusic {}                      — pause music playback
- skipForward {}                     — next track
- skipBackward {}                    — previous track
- openApp { appID }                  — open an app by BUNDLE ID
                                       (e.g. "com.spotify.client",
                                        "com.apple.mobilesafari",
                                        "com.apple.MobileSMS",
                                        "com.apple.Maps",
                                        "com.google.chrome.ios",
                                        "com.instagram.app")

Output schema (ALL fields required):
{
  "title": "<short title 3-5 words, suitable as iOS Shortcut name>",
  "summary": "<one short English sentence describing what the shortcut does, no more than 20 words>",
  "actions": [ {"action": "<name>", "params": {...}}, ... ],
  "aliases": [ "<5-10 short user phrases EN+IT that should trigger this shortcut>" ],
  "systemPurpose": "<lowercase_snake_case identifier capturing the canonical intent (e.g. torch_on, torch_off, dim_screen, play_pause_music, open_spotify_skip, good_night). Pick the closest existing GIGI intent if applicable; otherwise coin a new one.>"
}

Rules:
1. Output ONLY a JSON object. No prose, no markdown, no code fences. Just JSON.
2. summary: PLAIN ENGLISH ONLY. Used directly in the iOS proposal card. Avoid technical jargon.
3. actions: 1-6 entries, from the vocabulary above. If the request needs an action outside the vocabulary, do your best to approximate; if truly impossible, return "actions": [].
4. aliases: 5-10 phrases. Mix English (primary) and Italian (secondary). Each alias 1-4 words. No duplicates. Match what a user would naturally say to trigger this shortcut. NEVER include the literal word "build" / "create" / "make" / "shortcut" in the aliases — those are reserved for the build flow itself.
5. systemPurpose: canonical lowercase_snake_case identifier. If multiple shortcuts would naturally share it (e.g. two different torch-on shortcuts), still use the same purpose — the runtime registry handles dedup.
6. For openApp, ALWAYS use the bundle ID, not the friendly name.

Examples:

User: build me a shortcut that turns on the torch, waits 5 seconds, turns it off
Output:
{
  "title": "Quick Torch",
  "summary": "Turns the flashlight on for 5 seconds then off.",
  "actions": [
    {"action":"torchOn","params":{}},
    {"action":"waitSeconds","params":{"seconds":"5"}},
    {"action":"torchOff","params":{}}
  ],
  "aliases": ["torch on", "flashlight", "quick torch", "light on", "torcia", "accendi torcia", "flash on"],
  "systemPurpose": "torch_on"
}

User: make a shortcut that plays music and shows a notification saying "enjoy"
Output:
{
  "title": "Play & Notify",
  "summary": "Resumes music playback and shows an 'enjoy' notification.",
  "actions": [
    {"action":"playMusic","params":{}},
    {"action":"showNotification","params":{"text":"enjoy"}}
  ],
  "aliases": ["play music notify", "enjoy music", "start music notify", "musica e notifica"],
  "systemPurpose": "play_music_notify"
}

User: shortcut to open spotify and skip to next track
Output:
{
  "title": "Spotify Next",
  "summary": "Opens Spotify and skips to the next track.",
  "actions": [
    {"action":"openApp","params":{"appID":"com.spotify.client"}},
    {"action":"waitSeconds","params":{"seconds":"2"}},
    {"action":"skipForward","params":{}}
  ],
  "aliases": ["spotify next", "skip on spotify", "next track spotify", "salta canzone spotify"],
  "systemPurpose": "spotify_next"
}

User: a shortcut that dims the screen to 30% and tells me good night
Output:
{
  "title": "Good Night",
  "summary": "Dims the screen to 30% and speaks a 'good night' greeting.",
  "actions": [
    {"action":"setBrightness","params":{"brightness":"0.3"}},
    {"action":"speakText","params":{"text":"Good night, sleep well"}}
  ],
  "aliases": ["good night", "dim and goodnight", "buona notte", "abbassa luminosità notte"],
  "systemPurpose": "good_night"
}

OUTPUT JSON ONLY.`;

function extractFirstJsonObject(text) {
  if (!text) return null;
  // Strip code fences if any
  let s = String(text).trim();
  const fence = s.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (fence) s = fence[1].trim();
  // Find first { ... } with matching braces
  const start = s.indexOf('{');
  if (start < 0) return null;
  let depth = 0;
  for (let i = start; i < s.length; i++) {
    const ch = s[i];
    if (ch === '{') depth++;
    else if (ch === '}') {
      depth--;
      if (depth === 0) {
        const candidate = s.slice(start, i + 1);
        try { return JSON.parse(candidate); } catch { return null; }
      }
    }
  }
  return null;
}

async function composeWithClaude(cfg, rawText) {
  if (!cfg?.claude?.bin) {
    throw new Error('Claude CLI not configured in harness config (cfg.claude.bin).');
  }
  const userPrompt = `User request: ${String(rawText || '').trim()}\n\nOutput the JSON now.`;
  const args = [
    '-p', userPrompt,
    '--output-format', 'json',
    '--permission-mode', cfg.claude.permission_mode || 'bypassPermissions',
    '--append-system-prompt', COMPOSER_SYSTEM_PROMPT
  ];
  if (cfg.claude.model) args.push('--model', cfg.claude.model);

  logger.info(`composer spawning Claude for: ${String(rawText).slice(0, 80)}`);
  const res = await spawnClaude(cfg, args, null, null);
  if (res.code !== 0 && !res.stdout) {
    throw new Error(`Claude failed: ${res.stderr?.slice(0, 300) || res.error || 'exit ' + res.code}`);
  }

  // claude --output-format json returns a single JSON envelope on stdout
  // with a "result" string (the model's text reply).
  let resultText = '';
  try {
    const env = JSON.parse(res.stdout.trim());
    resultText = String(env.result || env.message || '').trim();
  } catch {
    // Fallback: take stdout as-is
    resultText = res.stdout.trim();
  }
  if (!resultText) throw new Error('Claude returned empty output.');

  const obj = extractFirstJsonObject(resultText);
  if (!obj) throw new Error('Claude output not valid JSON.');
  const title = String(obj.title || 'GIGI Shortcut').slice(0, 80);
  const actions = Array.isArray(obj.actions) ? obj.actions : [];
  if (actions.length === 0) throw new Error('Claude produced no actions.');
  // GATE 15 Step 4 metadata — used by iOS to render the proposal card and
  // to auto-register the installed shortcut in GigiShortcutRegistry.
  const summary = String(obj.summary || '').trim().slice(0, 240);
  const aliasesRaw = Array.isArray(obj.aliases) ? obj.aliases : [];
  const aliases = aliasesRaw
    .map((a) => String(a || '').trim())
    .filter((a) => a.length > 0 && a.length <= 40)
    .slice(0, 12);
  const systemPurpose = String(obj.systemPurpose || '')
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9_]+/g, '_')
    .replace(/^_+|_+$/g, '')
    .slice(0, 40);
  return { title, summary, actions, aliases, systemPurpose };
}

// MARK: - Unified job state machine (GATE 15 Smart Action Loop)
//
// One job, one id, walked through phases. EVERY phase boundary is short
// (POST returns immediately, client polls /job/<id> for progress) — so no
// HTTP call stays idle long enough for cellular NAT / Cloudflare tunnels
// to drop it (the -1005 NSURLErrorNetworkConnectionLost class of bug).
//
//   planning           ← Claude is composing the plan
//      ↓ Claude returns
//   awaiting_confirm   ← plan ready, iOS shows the proposal card
//      ↓ POST /build      ↓ POST /cancel
//   building           cancelled (terminal)
//      ↓ Mac signs
//   done (terminal)
//
// At any phase, an error transitions the job to `error` (terminal). 10-min
// TTL caps memory; we expect a job lifecycle to be well under 60s in practice.

const jobs = new Map();
const JOB_TTL_MS = 10 * 60 * 1000;

function pruneJobs() {
  const now = Date.now();
  for (const [id, j] of jobs.entries()) {
    if (j.expiresAt < now) jobs.delete(id);
  }
}

/**
 * Phase 1 (background) — Claude composes the plan, writes it onto the job.
 * Client polls /job/<id> until phase transitions to `awaiting_confirm`.
 */
async function runPlanPhase(jobId, ctx, rawText) {
  const job = jobs.get(jobId);
  if (!job) return;
  try {
    const composed = await composeWithClaude(ctx.cfg, rawText);
    // Validate vocabulary BEFORE handing the plan to iOS. If translation
    // fails we surface the error now, not after the user taps Build.
    const probeDsl = translateActionsToCherri(composed.title, composed.actions);
    if (!probeDsl) {
      job.phase = 'error';
      job.error = 'I can sketch this but one of the actions is outside my vocabulary. Try rephrasing.';
      return;
    }
    // job may have been cancelled while Claude was running — respect that
    if (jobs.get(jobId)?.phase === 'cancelled') return;
    job.title = composed.title;
    job.summary = composed.summary;
    job.actions = composed.actions;
    job.aliases = composed.aliases;
    job.systemPurpose = composed.systemPurpose;
    job.phase = 'awaiting_confirm';
    logger.info(`plan ${jobId} — title="${composed.title}" actions=${composed.actions.length} purpose=${composed.systemPurpose}`);
  } catch (e) {
    logger.error(`plan ${jobId} failed: ${e.message}`);
    job.phase = 'error';
    job.error = e.message;
  }
}

/**
 * Phase 2 (background) — User confirmed; compile + sign on the Mac.
 * Client keeps polling /job/<id> until phase transitions to `done`.
 */
async function runBuildPhase(jobId, ctx, req) {
  const job = jobs.get(jobId);
  if (!job) return;
  try {
    if (!Array.isArray(job.actions) || job.actions.length === 0) {
      job.phase = 'error';
      job.error = 'Internal: no plan attached to this job.';
      return;
    }
    const dsl = translateActionsToCherri(job.title, job.actions);
    if (!dsl) {
      job.phase = 'error';
      job.error = 'One of the generated actions is outside the Cherri vocabulary. Try rephrasing.';
      return;
    }
    logger.info(`build ${jobId} — ${job.actions.length} actions, DSL ${dsl.length} bytes`);
    const compiled = await compileAndSignOnMac(jobId, dsl);
    if (jobs.get(jobId)?.phase === 'cancelled') return;
    hostedFiles.set(jobId, {
      filePath: compiled.path,
      title: job.title,
      expiresAt: Date.now() + FILE_TTL_MS,
    });
    job.url = buildPublicShortcutURL(ctx, req, jobId);
    job.actionsCount = job.actions.length;
    job.phase = 'done';
  } catch (e) {
    logger.error(`build ${jobId} failed: ${e.message}`);
    job.phase = 'error';
    job.error = e.message;
  }
}

/**
 * LEGACY runner — supports the old POST /start path. Composes + builds
 * inline so existing IPAs (pre-GATE-15) keep working without re-pairing.
 */
async function runComposeJobLegacy(jobId, ctx, req, rawText, overrideTitle) {
  const job = jobs.get(jobId);
  if (!job) return;
  try {
    job.status = 'composing';
    const composed = await composeWithClaude(ctx.cfg, rawText);

    const title = (overrideTitle || composed.title || 'GIGI Shortcut').slice(0, 80);
    const dsl = translateActionsToCherri(title, composed.actions);
    if (!dsl) {
      job.status = 'error';
      job.error = 'One of the generated actions is outside the Cherri vocabulary. Try rephrasing.';
      return;
    }
    logger.info(`legacy composed ${jobId} — ${composed.actions.length} actions, DSL ${dsl.length} bytes`);

    job.status = 'signing';
    const compiled = await compileAndSignOnMac(jobId, dsl);
    hostedFiles.set(jobId, {
      filePath: compiled.path,
      title,
      expiresAt: Date.now() + FILE_TTL_MS,
    });

    job.status = 'done';
    job.title = title;
    job.summary = composed.summary;
    job.aliases = composed.aliases;
    job.systemPurpose = composed.systemPurpose;
    job.url = buildPublicShortcutURL(ctx, req, jobId);
    job.actionsCount = composed.actions.length;
  } catch (e) {
    logger.error(`job ${jobId} failed: ${e.message}`);
    job.status = 'error';
    job.error = e.message;
  }
}

// MARK: - Endpoint handlers (GATE 15 Smart Action Loop)

async function readJsonBody(req, res, maxLen = 4096) {
  let raw = '';
  for await (const chunk of req) {
    raw += chunk;
    if (raw.length > maxLen * 2) break;  // bail on absurd payloads
  }
  try { return JSON.parse(raw); }
  catch {
    res.writeHead(400, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: false, error: 'Invalid JSON' }));
    return null;
  }
}

/**
 * POST /api/ios/compose-shortcut/plan          (GATE 15 Step 2 — Plan Phase)
 *   Body: { rawText: String }
 *   Response 202: { ok, jobId }
 *
 * Returns IMMEDIATELY with a jobId; Claude composer runs in the
 * background. Client polls /job/<id> until phase becomes
 * `awaiting_confirm` (with the plan body) or `error`.
 *
 * Why this is async (and not the original sync version we shipped first):
 * Claude CLI takes 5-15s. A single sync POST that long gets dropped by
 * cellular NAT / Cloudflare quick tunnels (-1005 on iOS). The /job poll
 * keeps every HTTP call <2s.
 */
export async function handleComposeShortcutPlan(req, res, ctx) {
  const payload = await readJsonBody(req, res);
  if (!payload) return;

  const rawText = String(payload.rawText || '').trim();
  if (!rawText) {
    res.writeHead(400, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: false, error: 'Missing rawText' }));
    return;
  }
  if (rawText.length > 2000) {
    res.writeHead(413, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: false, error: 'rawText too large (max 2 KB)' }));
    return;
  }

  pruneJobs();
  const jobId = crypto.randomBytes(8).toString('hex');
  jobs.set(jobId, {
    id: jobId,
    phase: 'planning',
    rawText,
    createdAt: Date.now(),
    expiresAt: Date.now() + JOB_TTL_MS,
  });
  runPlanPhase(jobId, ctx, rawText).catch(() => {});

  res.writeHead(202, { 'Content-Type': 'application/json' });
  res.end(JSON.stringify({ ok: true, jobId }));
}

/**
 * POST /api/ios/compose-shortcut/build         (GATE 15 Step 3 — Build Phase)
 *   Body: { jobId: String }
 *   Response 202: { ok, jobId }   (echoes back the same id)
 *
 * Transitions a job from `awaiting_confirm` to `building`. Triggered when
 * the user taps "Build Shortcut" on the proposal card. cherri compile +
 * Mac sign run in the background; client keeps polling /job/<id> until
 * `done`.
 */
export async function handleComposeShortcutBuild(req, res, ctx) {
  const payload = await readJsonBody(req, res);
  if (!payload) return;

  const jobId = String(payload.jobId || payload.planId || '').trim();
  if (!/^[a-f0-9]{8,64}$/.test(jobId)) {
    res.writeHead(400, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: false, error: 'Missing or malformed jobId' }));
    return;
  }
  pruneJobs();
  const job = jobs.get(jobId);
  if (!job) {
    res.writeHead(410, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: false, error: 'Plan expired. Ask me again to start over.' }));
    return;
  }
  if (job.phase !== 'awaiting_confirm') {
    res.writeHead(409, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: false, error: `Cannot build in phase '${job.phase}'.` }));
    return;
  }

  job.phase = 'building';
  runBuildPhase(jobId, ctx, req).catch(() => {});

  res.writeHead(202, { 'Content-Type': 'application/json' });
  res.end(JSON.stringify({ ok: true, jobId }));
}

/**
 * POST /api/ios/compose-shortcut/cancel
 *   Body: { jobId: String }
 *   Response 200: { ok: true }
 *
 * Marks the job as cancelled (terminal). Any in-flight Claude or cherri
 * call finishes naturally but its result is discarded by the runners.
 */
export async function handleComposeShortcutCancel(req, res, _ctx) {
  const payload = await readJsonBody(req, res);
  if (!payload) return;
  const jobId = String(payload.jobId || payload.planId || '').trim();
  const job = jobId ? jobs.get(jobId) : null;
  if (job) {
    job.phase = 'cancelled';
    // Keep the entry around briefly so a final poll sees the terminal
    // state, then let pruneJobs clean it up at TTL.
    logger.info(`job ${jobId} cancelled by client`);
  }
  res.writeHead(200, { 'Content-Type': 'application/json' });
  res.end(JSON.stringify({ ok: true }));
}

/**
 * POST /api/ios/compose-shortcut/start         (LEGACY — pre-GATE-15 IPAs)
 *   Body: { rawText: String, title?: String }
 *   Response 202: { ok: true, jobId }
 *
 * Composes + builds inline (no proposal card). Kept so older clients
 * keep working without re-pairing. New IPAs should use /plan + /build.
 */
export async function handleComposeShortcutStart(req, res, ctx) {
  const payload = await readJsonBody(req, res);
  if (!payload) return;

  const rawText = String(payload.rawText || '').trim();
  if (!rawText) {
    res.writeHead(400, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: false, error: 'Missing rawText' }));
    return;
  }
  if (rawText.length > 2000) {
    res.writeHead(413, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: false, error: 'rawText too large (max 2 KB)' }));
    return;
  }

  pruneJobs();
  const jobId = crypto.randomBytes(8).toString('hex');
  jobs.set(jobId, {
    id: jobId,
    status: 'pending',
    expiresAt: Date.now() + JOB_TTL_MS,
  });
  runComposeJobLegacy(jobId, ctx, req, rawText, String(payload.title || '').trim()).catch(() => {});

  res.writeHead(202, { 'Content-Type': 'application/json' });
  res.end(JSON.stringify({ ok: true, jobId }));
}

/**
 * GET /api/ios/compose-shortcut/job/<id>
 *   Response 200: { ok: true, status, phase, ...payload }
 *
 * Unified poll endpoint. `phase` is the new GATE 15 state machine name
 * (planning | awaiting_confirm | building | done | cancelled | error);
 * `status` is the legacy field kept for backward-compat with older IPAs
 * that still understand pending|composing|signing|done|error.
 *
 * Payload depends on phase:
 *   - awaiting_confirm: { title, summary, actions, aliases, systemPurpose }
 *     iOS shows the proposal card from this payload.
 *   - done: { url, title, summary, aliases, systemPurpose, actionsCount }
 *     iOS downloads the signed file and auto-registers (Learn Phase).
 *   - cancelled | error: { error? }
 */
export async function handleComposeShortcutJob(req, res, _ctx) {
  pruneJobs();
  const url = new URL(req.url, `http://${req.headers.host}`);
  const m = url.pathname.match(/^\/api\/ios\/compose-shortcut\/job\/([a-f0-9]+)$/);
  if (!m) { res.writeHead(404); res.end(); return; }
  const job = jobs.get(m[1]);
  if (!job) {
    res.writeHead(404, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: false, error: 'Job not found or expired' }));
    return;
  }
  // New flow uses `phase`; legacy /start runner uses `status`. Read both.
  const phase = job.phase || job.status || 'pending';
  const body = { ok: true, jobId: job.id, phase, status: phase };
  if (phase === 'awaiting_confirm') {
    body.title = job.title || '';
    body.summary = job.summary || '';
    body.actions = job.actions || [];
    body.aliases = job.aliases || [];
    body.systemPurpose = job.systemPurpose || '';
  } else if (phase === 'done') {
    body.url = job.url;
    body.title = job.title;
    body.summary = job.summary;
    body.aliases = job.aliases || [];
    body.systemPurpose = job.systemPurpose || '';
    body.actionsCount = job.actionsCount;
  } else if (phase === 'cancelled') {
    body.cancelled = true;
  } else if (phase === 'error') {
    body.error = job.error;
  }
  res.writeHead(200, { 'Content-Type': 'application/json' });
  res.end(JSON.stringify(body));
}

/**
 * Legacy synchronous endpoint — kept for backward compat with the iOS
 * a810eee build that doesn't yet know about /start + /job/<id>. Same
 * behavior as before, just routes through the same job runner inline.
 *
 * POST /api/ios/compose-shortcut
 *   Body: { rawText: String, title?: String }
 *   Response 200: { ok: true, url, id, title }
 */
export async function handleComposeShortcut(req, res, ctx) {
  let raw = '';
  for await (const chunk of req) raw += chunk;

  let payload;
  try { payload = JSON.parse(raw); }
  catch {
    res.writeHead(400, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: false, error: 'Invalid JSON' }));
    return;
  }

  const rawText = String(payload.rawText || '').trim();
  if (!rawText) {
    res.writeHead(400, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: false, error: 'Missing rawText' }));
    return;
  }
  if (rawText.length > 2000) {
    res.writeHead(413, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: false, error: 'rawText too large (max 2 KB)' }));
    return;
  }

  const id = crypto.randomBytes(8).toString('hex');

  let composed;
  try {
    composed = await composeWithClaude(ctx.cfg, rawText);
  } catch (e) {
    logger.error(`compose failed: ${e.message}`);
    res.writeHead(502, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: false, error: `Composer failed: ${e.message}` }));
    return;
  }

  const overrideTitle = String(payload.title || '').trim();
  const title = (overrideTitle || composed.title || 'GIGI Shortcut').slice(0, 80);

  const dsl = translateActionsToCherri(title, composed.actions);
  if (!dsl) {
    res.writeHead(422, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: false, error: 'One of the generated actions is outside the Cherri vocabulary. Try rephrasing.' }));
    return;
  }

  logger.info(`composed ${id} — ${composed.actions.length} actions, DSL ${dsl.length} bytes`);

  try {
    const compiled = await compileAndSignOnMac(id, dsl);
    hostedFiles.set(id, {
      filePath: compiled.path,
      title,
      expiresAt: Date.now() + FILE_TTL_MS
    });

    const url = buildPublicShortcutURL(ctx, req, id);

    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: true, url, id, title, actionsCount: composed.actions.length }));
  } catch (e) {
    logger.error(`compose-sign failed: ${e.message}`);
    res.writeHead(500, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: false, error: `Sign failed: ${e.message}` }));
  }
}

/**
 * Build the public URL the iOS app will hand to Shortcuts.app.
 *
 * Must be HTTPS — iOS App Transport Security blocks HTTP fetches inside
 * Shortcuts.app, and `shortcuts://import-shortcut/?url=` rejects non-https
 * URLs silently with "URL not valid".
 *
 * Precedence:
 *   1. cfg.publicBaseURL (operator-supplied, e.g. an https://*.com domain)
 *   2. x-forwarded-proto + Host (Cloudflare Tunnel sets these on inbound)
 *   3. Default to https://<host> — only falls to http if Host is a literal
 *      127.0.0.1/localhost (where iOS would never reach anyway)
 */
function buildPublicShortcutURL(ctx, req, id) {
  if (ctx.cfg?.publicBaseURL) {
    const base = String(ctx.cfg.publicBaseURL).replace(/\/$/, '');
    return `${base}/api/ios/build-shortcut/${id}.shortcut`;
  }
  const host = String(req.headers.host || 'localhost:7779');
  const fwdProto = String(req.headers['x-forwarded-proto'] || '').split(',')[0].trim();
  const isLocal = /^(?:localhost|127\.0\.0\.1|\[::1\])(?::\d+)?$/i.test(host);
  let proto;
  if (fwdProto) proto = fwdProto;
  else if (isLocal) proto = 'http';
  else proto = 'https';                 // Cloudflare tunnel, public domain, etc.
  return `${proto}://${host}/api/ios/build-shortcut/${id}.shortcut`;
}

export async function handleBuildShortcut(req, res, ctx) {
  // Drain body (the router has already done some, but keep robust).
  let raw = '';
  for await (const chunk of req) raw += chunk;

  let payload;
  try {
    payload = JSON.parse(raw);
  } catch (e) {
    res.writeHead(400, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: false, error: 'Invalid JSON' }));
    return;
  }

  const title = String(payload.title || 'GIGI Shortcut').slice(0, 80);
  const dsl = String(payload.dsl || '').trim();
  if (!dsl) {
    res.writeHead(400, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: false, error: 'Missing DSL' }));
    return;
  }
  if (dsl.length > 100_000) {
    res.writeHead(413, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: false, error: 'DSL too large (max 100 KB)' }));
    return;
  }

  const id = crypto.randomBytes(8).toString('hex');

  try {
    const compiled = await compileAndSignOnMac(id, dsl);
    hostedFiles.set(id, {
      filePath: compiled.path,
      title,
      expiresAt: Date.now() + FILE_TTL_MS
    });

    const url = buildPublicShortcutURL(ctx, req, id);

    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: true, url, id, title }));
  } catch (e) {
    logger.error(`compile failed: ${e.message}`);
    res.writeHead(500, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: false, error: `Compile failed: ${e.message}` }));
  }
}

/**
 * Serves the signed .shortcut file. Triggered by iOS UIApplication.open
 * when the iOS app received the URL from /build-shortcut POST.
 *
 * Path format: /api/ios/build-shortcut/<id>.shortcut
 */
export async function handleShortcutFile(req, res, _ctx) {
  pruneExpired();

  const url = new URL(req.url, `http://${req.headers.host}`);
  const m = url.pathname.match(/^\/api\/ios\/build-shortcut\/([a-f0-9]+)\.shortcut$/);
  if (!m) {
    res.writeHead(404);
    res.end();
    return;
  }
  const id = m[1];
  const entry = hostedFiles.get(id);
  if (!entry || entry.expiresAt < Date.now()) {
    res.writeHead(410);  // Gone — file expired
    res.end();
    return;
  }

  let bytes;
  try {
    bytes = await fs.readFile(entry.filePath);
  } catch (e) {
    res.writeHead(500);
    res.end();
    return;
  }

  const niceName = entry.title.replace(/[^\w\s-]/g, '').replace(/\s+/g, '-').slice(0, 40) || 'GIGI-Shortcut';
  res.writeHead(200, {
    // Apple Shortcuts signed (AEA1) file. iOS detects via .shortcut
    // filename + magic bytes; octet-stream is the safe generic MIME used
    // by RoutineHub and the iCloud gallery. attachment disposition tells
    // Safari to download + invoke the system handler instead of trying
    // to render the binary inline.
    'Content-Type': 'application/octet-stream',
    'Content-Disposition': `attachment; filename="${niceName}.shortcut"`,
    'Cache-Control': 'no-store, no-cache, must-revalidate',
    'Content-Length': bytes.length
  });
  res.end(bytes);
}
